#include <stdio.h>
#include <stdint.h>

// Simulated hardware registers
volatile uint32_t *DMA_SRC_ADDR = (uint32_t *)0x40001000;
volatile uint32_t *DMA_DST_ADDR = (uint32_t *)0x40001004;
volatile uint32_t *DMA_COUNT   = (uint32_t *)0x40001008;
volatile uint32_t *DMA_CTRL    = (uint32_t *)0x4000100C;

#define DMA_START    0x00000001
#define DMA_COMPLETE 0x00000002

// Transfer buffer (simulating memory)
uint8_t source_buffer[1024] = {1, 2, 3, 4, 5};
uint8_t dest_buffer[1024] = {0};

// CPU continues other work while DMA transfers
void cpu_work() {
    printf("CPU performing other tasks...\n");
    for(volatile int i=0; i<1000; i++);  // Simulated work
    printf("CPU work done.\n");
}

void dma_transfer阻塞(uint32_t src, uint32_t dst, uint32_t count) {
    // Configure DMA transfer
    *DMA_SRC_ADDR = src;
    *DMA_DST_ADDR = dst;
    *DMA_COUNT   = count;
    *DMA_CTRL    = DMA_START;

    // Polling for completion (in real systems, interrupt would be used)
    while(!(*DMA_CTRL & DMA_COMPLETE));

    printf("DMA transfer complete!\n");
}

int main() {
    printf("Starting DMA transfer demo\n");

    // Without DMA: CPU would need to copy byte by byte
    // With DMA: CPU can do other work

    dma_transfer((uint32_t)source_buffer, (uint32_t)dest_buffer, 5);

    printf("Destination buffer: ");
    for(int i=0; i<5; i++) printf("%d ", dest_buffer[i]);
    printf("\n");

    return 0;
}

public class InterruptDemo {
    // Simulated hardware registers
    private static boolean interruptFlag = false;
    private static int dataBuffer = 0;

    // Interrupt Service Routine (ISR)
    public static void handleInterrupt() {
        System.out.println("[ISR] Interrupt received!");
        // Save CPU state (simulated)
        int savedPC = 0; // Would save actual PC in real system

        // Handle the interrupt
        if (interruptFlag) {
            dataBuffer = readFromDevice();
            System.out.println("[ISR] Data received: " + dataBuffer);
            interruptFlag = false;
        }

        // Restore CPU state and return
        System.out.println("[ISR] Returning to main program\n");
    }

    private static int readFromDevice() {
        // Simulate I/O device data
        return (int)(Math.random() * 100);
    }

    // Main program execution
    public static void main(String[] args) throws InterruptedException {
        System.out.println("=== INTERRUPT-BASED I/O DEMO ===\n");

        // Simulate program doing useful work
        for (int i = 1; i <= 3; i++) {
            System.out.println("Main: Performing computation " + i);
            Thread.sleep(500);

            // Randomly generate interrupt (like hardware event)
            if (Math.random() > 0.5) {
                interruptFlag = true;
                handleInterrupt(); // CPU responds to interrupt
            }
        }

        System.out.println("\n=== POLLING-BASED I/O DEMO (Inefficient) ===\n");

        // Polling approach - wastes CPU cycles
        for (int i = 1; i <= 3; i++) {
            System.out.println("Main: Checking device status...");

            // CPU continuously polls instead of doing useful work
            while (!interruptFlag) {
                // Busy wait - CPU doing nothing useful
            }

            dataBuffer = readFromDevice();
            System.out.println("Main: Data received: " + dataBuffer);
            interruptFlag = false;
            Thread.sleep(500);
        }
    }
}
